/**
 * Per-entity integration **change-emitter** emitter (EMIT-CHANGES seam).
 *
 * Per (surface, entity-with-`surface:` + `pattern: Integrated`) that opts into
 * `integration.sink.emit_changes: true`, emits the TEXT of
 * `src/integrations/<surface>/sinks/<entity>.change-emitter.ts` — a FULLY
 * `@generated` `IIntegrationChangeEmitter` over the consumer's generated
 * `TypedEventBus`.
 *
 * ## What it does
 *
 * The integration orchestrator (`ExecuteIntegrationUseCase`) is provider- AND
 * entity-agnostic — `entityType` is a bare `string` — so it cannot publish a
 * typed `<entity>_created` event itself. This generated adapter closes that gap:
 * it maps the orchestrator's `IntegrationChangeNotification.action`
 * (`created | updated | deleted`) onto the typed event name
 * (`<entity>_created` / `<entity>_edited` / `<entity>_deleted` — `_edited`, NOT
 * `_updated`, per swe-brain ADR-0009 B1) and calls the consumer's typed bus.
 *
 * The payload is `{ entityId, externalId, provider, changedFields?, source:
 * 'integration' }` — the provenance marker `source` lets a future write-back
 * action detect integration-originated changes and break the inbound→writeback
 * loop. `changedFields` is forwarded only for created/edited (deletes are
 * tombstones with no diff). The published `aggregateId` is the local entity id.
 *
 * ## Wiring
 *
 * The per-entity assembly module binds this class to `INTEGRATION_CHANGE_EMITTER`
 * (see `assembly-emission-generator.ts`), injecting the `TYPED_EVENT_BUS` token
 * (bound globally by `EventsModule.forRoot()`). The orchestrator injects the
 * token `@Optional()`, so an entity that does NOT opt in binds nothing and
 * publishes nothing (the back-compat default).
 *
 * ## Pure emitter
 *
 * String-builder only — names + mode arrive as params; the caller
 * (`emitAdapters`) owns all filesystem wiring. Fully `@generated`
 * (`writeIfChanged`), NOT an emit-once scaffold: the event-name mapping and
 * payload are mechanical, with no author seam (the author seam is the EVENT
 * DEFINITION — a top-level `events/<entity>_created.yaml` overrides the generated
 * triad via mergeEvents' top-level-wins policy).
 */

import { subsystemsImport, type RuntimeMode } from "./runtime-import";

// ============================================================================
// Banner
// ============================================================================

function generatedBanner(sourceDesc: string): string {
  return (
    `// @generated by @pattern-stack/codegen from ${sourceDesc} — DO NOT EDIT.\n` +
    `// Hand edits are overwritten on re-emit. Regenerate with \`bun run codegen\`.`
  );
}

// ============================================================================
// Input
// ============================================================================

/** Pure input for {@link generateChangeEmitter}. */
export interface ChangeEmitterEmitInput {
  /** Entity name, snake_case singular (`message`). Drives the event-type names. */
  entityName: string;
  /** PascalCase entity class (`Message`). Drives the emitter class name. */
  entityClass: string;
  /** Surface tag (`messaging`). For the doc banner only. */
  surface: string;
  /** Source descriptor for the @generated banner. */
  sourceDesc: string;
  /** Runtime mode (ADR-037) — selects the events + integration subsystem import
   *  specifiers. Defaults to `package` when omitted. */
  mode?: RuntimeMode;
}

// ============================================================================
// Names
// ============================================================================

/** The generated emitter class name for an entity, e.g. `MessageChangeEmitter`. */
export function changeEmitterClass(entityClass: string): string {
  return `${entityClass}ChangeEmitter`;
}

// ============================================================================
// Emitter
// ============================================================================

/**
 * Emit the fully-`@generated` `IIntegrationChangeEmitter` for an
 * `emit_changes: true` entity. Maps the orchestrator's change action onto the
 * typed `<entity>_<verb>` event and publishes via the consumer's `TypedEventBus`.
 */
export function generateChangeEmitter(input: ChangeEmitterEmitInput): string {
  const mode = input.mode ?? "package";
  const cls = changeEmitterClass(input.entityClass);
  const eventsImport = subsystemsImport(mode, "events");
  const integrationImport = subsystemsImport(mode, "integration");

  const createdType = `${input.entityName}_created`;
  const editedType = `${input.entityName}_edited`;
  const deletedType = `${input.entityName}_deleted`;

  return `${generatedBanner(input.sourceDesc)}
import { Inject, Injectable } from '@nestjs/common';
import { TYPED_EVENT_BUS } from '${eventsImport}';
import type {
  IIntegrationChangeEmitter,
  IntegrationChangeNotification,
} from '${integrationImport}';

/**
 * Minimal publisher shape the emitter calls — decoupled from BOTH the package's
 * \`TypedEventBus\` (whose \`EventTypeName\` union is the package's own events) and
 * the consumer's generated \`TypedEventBus\` (whose union is the consumer's
 * events). The \`${createdType}\` / \`${editedType}\` / \`${deletedType}\` events
 * THIS class publishes live in the CONSUMER's registry; the structural \`publish\`
 * here accepts the string types without depending on either compile-time union.
 * The TYPED_EVENT_BUS token resolves to the consumer's generated bus at runtime
 * (bound by EventsModule.forRoot()), which validates the payload against the
 * generated event schema.
 */
interface ChangeEventPublisher {
  publish(
    type: string,
    aggregateId: string,
    payload: Record<string, unknown>,
    opts?: { tx?: unknown; metadata?: Record<string, unknown> },
  ): Promise<void>;
}

/**
 * ${cls} — publishes the typed ${input.entityName} data-level change events
 * (\`${createdType}\` / \`${editedType}\` / \`${deletedType}\`) after the
 * integration orchestrator's sink write/soft-delete (EMIT-CHANGES seam).
 *
 * Bound to INTEGRATION_CHANGE_EMITTER in the ${input.entityName} integration
 * assembly; the orchestrator calls \`emitChange\` once per real change. The
 * payload carries \`source: 'integration'\` so a write-back action can detect an
 * integration-originated change and decline to echo it back to the vendor.
 */
@Injectable()
export class ${cls} implements IIntegrationChangeEmitter {
  constructor(
    @Inject(TYPED_EVENT_BUS) private readonly bus: ChangeEventPublisher,
  ) {}

  async emitChange(notification: IntegrationChangeNotification): Promise<void> {
    const type =
      notification.action === 'created'
        ? '${createdType}'
        : notification.action === 'updated'
          ? '${editedType}'
          : '${deletedType}';

    const payload: Record<string, unknown> = {
      entityId: notification.entityId,
      externalId: notification.externalId,
      provider: notification.provider,
      source: 'integration',
    };
    // changedFields is present on created/edited only (deletes are tombstones).
    if (notification.changedFields !== undefined) {
      payload['changedFields'] = notification.changedFields;
    }

    await this.bus.publish(type, notification.entityId, payload, {
      tx: notification.tx,
      metadata:
        notification.tenantId !== undefined && notification.tenantId !== null
          ? { tenantId: notification.tenantId }
          : undefined,
    });
  }
}
`;
}
